1	import { useState, useCallback, useRef, useEffect } from 'react';
2	
3	export interface Message {
4	  id: string;
5	  role: 'user' | 'assistant';
6	  text: string;
7	  timestamp: Date;
8	}
9	
10	interface UseOpenClawResult {
11	  messages: Message[];
12	  sendMessage: (text: string) => void;
13	  isConnected: boolean;
14	  isTyping: boolean;
15	}
16	
17	// Webhook sunucu adresleri (middleware ile güvenli bağlantı)
18	const WEBHOOK_WS = 'ws://127.0.0.1:3002';
19	const WEBHOOK_API = 'http://127.0.0.1:3001';
20	const RECONNECT_DELAY_MS = 3000;
21	const MAX_RECONNECT_ATTEMPTS = 10;
22	
23	export function useOpenClaw(_planActions: any): UseOpenClawResult {
24	  const [messages, setMessages] = useState<Message[]>([]);
25	  const [isConnected, setIsConnected] = useState(false);
26	  const [isTyping, setIsTyping] = useState(false);
27	
28	  const wsRef = useRef<WebSocket | null>(null);
29	  const reqIdRef = useRef(0);
30	  const handshakeDoneRef = useRef(false);
31	  const reconnectAttempts = useRef(0);
32	  const reconnectTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
33	  const mountedRef = useRef(true);
34	
35	  // ─── Gateway'e Doğrudan WebSocket Bağlantısı ───
36	  const connect = useCallback(() => {
37	    if (
38	      wsRef.current &&
39	      (wsRef.current.readyState === WebSocket.OPEN ||
40	        wsRef.current.readyState === WebSocket.CONNECTING)
41	    ) {
42	      return;
43	    }
44	
45	    try {
46	      const ws = new WebSocket(WEBHOOK_WS);
47	      wsRef.current = ws;
48	
49	      ws.onopen = () => {
50	        if (!mountedRef.current) return;
51	        console.log('[OpenClaw] ✓ Webhook sunucusuna bağlandı');
52	        setIsConnected(true);
53	        handshakeDoneRef.current = true;
54	        reconnectAttempts.current = 0;
55	      };
56	
57	      ws.onmessage = (event: MessageEvent) => {
58	        if (!mountedRef.current) return;
59	
60	        try {
61	          const data = JSON.parse(event.data);
62	
63	          if (data.type === 'response' && data.text) {
64	            setIsTyping(false);
65	            setMessages(prev => [
66	              ...prev,
67	              {
68	                id: data.id || crypto.randomUUID(),
69	                role: 'assistant',
70	                text: data.text,
71	                timestamp: new Date(data.timestamp || Date.now()),
72	              },
73	            ]);
74	          } else if (data.type === 'error') {
75	            setIsTyping(false);
76	            setMessages(prev => [
77	              ...prev,
78	              {
79	                id: crypto.randomUUID(),
80	                role: 'assistant',
81	                text: data.text || '⚠️ Bir hata oluştu',
82	                timestamp: new Date(),
83	              },
84	            ]);
85	          }
86	        } catch {
87	          console.log('[OpenClaw] Ayrılamayan yanıt:', event.data);
88	        }
89	      };
90	
91	      ws.onclose = () => {
92	        if (!mountedRef.current) return;
93	        console.log('[OpenClaw] ✗ Bağlantı kapandı');
94	        setIsConnected(false);
95	        setIsTyping(false);
96	        handshakeDoneRef.current = false;
97	        wsRef.current = null;
98	
99	        if (reconnectAttempts.current < MAX_RECONNECT_ATTEMPTS) {
100	          const delay =
101	            RECONNECT_DELAY_MS *
102	            Math.min(Math.pow(1.5, reconnectAttempts.current), 10);
103	          reconnectAttempts.current++;
104	          console.log(
105	            `[OpenClaw] ${Math.round(delay / 1000)}s sonra tekrar denenecek… (${reconnectAttempts.current}/${MAX_RECONNECT_ATTEMPTS})`
106	          );
107	          reconnectTimer.current = setTimeout(() => {
108	            if (mountedRef.current) connect();
109	          }, delay);
110	        } else {
111	          console.log('[OpenClaw] Maksimum yeniden bağlanma denemesine ulaşıldı.');
112	        }
113	      };
114	
115	      ws.onerror = () => {
116	        if (!mountedRef.current) return;
117	        console.error('[OpenClaw] WebSocket hatası');
118	      };
119	    } catch (err) {
120	      console.error('[OpenClaw] Bağlantı kurulamadı:', err);
121	      setIsConnected(false);
122	    }
123	  }, []);
124	
125	  // ─── Mount/Unmount ───
126	  useEffect(() => {
127	    mountedRef.current = true;
128	    connect();
129	
130	    return () => {
131	      mountedRef.current = false;
132	      if (reconnectTimer.current) {
133	        clearTimeout(reconnectTimer.current);
134	      }
135	      if (wsRef.current) {
136	        wsRef.current.close(1000, 'Component unmount');
137	        wsRef.current = null;
138	      }
139	    };
140	  }, [connect]);
141	
142	  // ─── Mesaj Gönder (Webhook sunucu üzerinden HTTP) ───
143	  const sendMessage = useCallback(
144	    (text: string) => {
145	      if (!text.trim()) return;
146	
147	      const userMsg: Message = {
148	        id: crypto.randomUUID(),
149	        role: 'user',
150	        text,
151	        timestamp: new Date(),
152	      };
153	      setMessages(prev => [...prev, userMsg]);
154	
155	      if (isConnected) {
156	        setIsTyping(true);
157	        fetch(`${WEBHOOK_API}/api/message`, {
158	          method: 'POST',
159	          headers: { 'Content-Type': 'application/json' },
160	          body: JSON.stringify({ text }),
161	        })
162	          .catch(err => {
163	            console.error('[OpenClaw] Webhook gönderim hatası:', err);
164	            setIsTyping(false);
165	            setMessages(prev => [
166	              ...prev,
167	              {
168	                id: crypto.randomUUID(),
169	                role: 'assistant',
170	                text: '⚠️ Mesaj gönderilemedi. Sunucu yanıt vermiyor.',
171	                timestamp: new Date(),
172	              },
173	            ]);
174	          });
175	      } else {
176	        setMessages(prev => [
177	          ...prev,
178	          {
179	            id: crypto.randomUUID(),
180	            role: 'assistant',
181	            text: '⚠️ Bağlantı kesildi. Yeniden bağlanılıyor…',
182	            timestamp: new Date(),
183	          },
184	        ]);
185	        reconnectAttempts.current = 0;
186	        connect();
187	      }
188	    },
189	    [isConnected, connect]
190	  );
191	
192	  return { messages, sendMessage, isConnected, isTyping };
193	}
