/**
 * OpenClaw Proxy Server
 * - Frontend'ten gelen mesajları OpenClaw Gateway'in OpenAI-uyumlu endpoint'ine iletir
 * - CORS'u yönetir, token'ı güvende tutar (browser'a sızdırmaz)
 * - Telegram bot mantığı: mesaj gönder → cevap al
 */
import express from 'express';
import http from 'http';
import 'dotenv/config';

const app = express();
const server = http.createServer(app);

const PORT = Number(process.env.WEBHOOK_PORT || 3001);
const GATEWAY_URL = process.env.OPENCLAW_GATEWAY_URL || 'http://127.0.0.1:18789';
const TOKEN = process.env.OPENCLAW_TOKEN || '';
const MODEL = process.env.OPENCLAW_MODEL || 'openclaw';
const ALLOWED_ORIGIN = process.env.CORS_ORIGIN || '*';

if (!TOKEN) {
  console.error('\n❌ OPENCLAW_TOKEN eksik!');
  console.error('   .env.local dosyasına ekleyin:');
  console.error('   OPENCLAW_TOKEN="your_token_here"\n');
  process.exit(1);
}

// ─── Middleware ───
app.use((req, res, next) => {
  res.header('Access-Control-Allow-Origin', ALLOWED_ORIGIN);
  res.header('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
  res.header('Access-Control-Allow-Headers', 'Content-Type');
  if (req.method === 'OPTIONS') return res.sendStatus(200);
  next();
});

app.use(express.json({ limit: '2mb' }));

// ─── POST /api/message ───
// Body: { text: string } veya { messages: [{role, content}, ...] }
// Cevap: { reply: string, raw: openai-response }
app.post('/api/message', async (req, res) => {
  const { text, messages } = req.body ?? {};

  const payload = Array.isArray(messages) && messages.length > 0
    ? messages
    : typeof text === 'string' && text.trim()
      ? [{ role: 'user', content: text }]
      : null;

  if (!payload) {
    return res.status(400).json({ error: 'text veya messages gerekli' });
  }

  try {
    const gwRes = await fetch(`${GATEWAY_URL}/v1/chat/completions`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${TOKEN}`,
      },
      body: JSON.stringify({
        model: MODEL,
        messages: payload,
        stream: false,
      }),
    });

    if (!gwRes.ok) {
      const errText = await gwRes.text();
      console.error(`[Gateway] ${gwRes.status}:`, errText);
      return res.status(gwRes.status).json({
        error: `Gateway hata: ${gwRes.status}`,
        detail: errText.slice(0, 500),
      });
    }

    const data: any = await gwRes.json();
    const reply = data?.choices?.[0]?.message?.content ?? '';
    console.log(`[Gateway] ✓ ${String(payload[payload.length - 1]?.content).slice(0, 40)}... → ${reply.slice(0, 40)}...`);
    res.json({ reply, raw: data });
  } catch (err: any) {
    console.error('[Gateway] Fetch hatası:', err?.message);
    res.status(502).json({
      error: 'Gateway yanıt vermedi',
      detail: err?.message || String(err),
    });
  }
});

// ─── GET /api/status ───
app.get('/api/status', async (_req, res) => {
  try {
    const r = await fetch(`${GATEWAY_URL}/v1/models`, {
      headers: { Authorization: `Bearer ${TOKEN}` },
    });
    res.json({
      gateway: r.ok ? 'connected' : 'error',
      status: r.status,
      url: GATEWAY_URL,
    });
  } catch (err: any) {
    res.json({
      gateway: 'disconnected',
      error: err?.message || String(err),
      url: GATEWAY_URL,
    });
  }
});

// ─── Başlat ───
server.listen(PORT, () => {
  console.log(`\n🦞 OpenClaw Proxy Server`);
  console.log(`   HTTP:    http://localhost:${PORT}`);
  console.log(`   Gateway: ${GATEWAY_URL}`);
  console.log(`   Model:   ${MODEL}\n`);
});

import { useState, useCallback, useEffect, useRef } from 'react';

export interface Message {
  id: string;
  role: 'user' | 'assistant';
  text: string;
  timestamp: Date;
}

interface UseOpenClawResult {
  messages: Message[];
  sendMessage: (text: string) => void;
  isConnected: boolean;
  isTyping: boolean;
}

// Proxy server (server/webhook-server.ts)
const PROXY_API = (import.meta as any).env?.VITE_OPENCLAW_PROXY || 'http://127.0.0.1:3001';
const HEALTH_INTERVAL_MS = 15_000;

export function useOpenClaw(_planActions: any): UseOpenClawResult {
  const [messages, setMessages] = useState<Message[]>([]);
  const [isConnected, setIsConnected] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const messagesRef = useRef<Message[]>([]);

  // messages state'ini ref'te tut, sendMessage stabil kalsın
  useEffect(() => {
    messagesRef.current = messages;
  }, [messages]);

  // ─── Health check ───
  useEffect(() => {
    let alive = true;

    const check = async () => {
      try {
        const r = await fetch(`${PROXY_API}/api/status`);
        if (!alive) return;
        const data = await r.json();
        setIsConnected(data.gateway === 'connected');
      } catch {
        if (alive) setIsConnected(false);
      }
    };

    check();
    const id = setInterval(check, HEALTH_INTERVAL_MS);
    return () => {
      alive = false;
      clearInterval(id);
    };
  }, []);

  // ─── Mesaj gönder (Telegram bot mantığı: gönder → cevap bekle) ───
  const sendMessage = useCallback((text: string) => {
    if (!text.trim()) return;

    const userMsg: Message = {
      id: crypto.randomUUID(),
      role: 'user',
      text,
      timestamp: new Date(),
    };
    setMessages(prev => [...prev, userMsg]);
    setIsTyping(true);

    const history = [...messagesRef.current, userMsg].map(m => ({
      role: m.role,
      content: m.text,
    }));

    fetch(`${PROXY_API}/api/message`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ messages: history }),
    })
      .then(async r => {
        if (!r.ok) {
          const err = await r.json().catch(() => ({}));
          throw new Error(err.error || `HTTP ${r.status}`);
        }
        return r.json();
      })
      .then((data: { reply?: string }) => {
        setMessages(prev => [
          ...prev,
          {
            id: crypto.randomUUID(),
            role: 'assistant',
            text: data.reply?.trim() || '(Yanıt boş)',
            timestamp: new Date(),
          },
        ]);
      })
      .catch((err: Error) => {
        console.error('[OpenClaw] Hata:', err);
        setMessages(prev => [
          ...prev,
          {
            id: crypto.randomUUID(),
            role: 'assistant',
            text: `⚠️ ${err.message || 'Bağlantı hatası'}`,
            timestamp: new Date(),
          },
        ]);
      })
      .finally(() => setIsTyping(false));
  }, []);

  return { messages, sendMessage, isConnected, isTyping };
}

